const analystenDaten = items.map(item => item.json);

const formattedOutput = analystenDaten.map(item =>
  `${item.period}: Stark Kaufen: ${item.strongBuy}, Kaufen: ${item.buy}, Halten: ${item.hold}, Verkaufen: ${item.sell}, Stark Verkaufen: ${item.strongSell}`
).join("\n");

return [{ json: { output: formattedOutput } }];

const metrics = $json["metric"];
const relevanteDaten = {
  // Bei Marktkapitalisierung direkt "USD" ergänzen.
  Marktkapitalisierung: metrics.marketCapitalization + " USD",

  // KGV, KUV, KBV, Beta: keine Einheit (Verhältniszahlen).
  KGV_TTM: metrics.peTTM,
  KUV_TTM: metrics.psTTM,
  KBV_TTM: metrics.pbQuarterly,

  // Wachstum & Margen: in Prozent.
  Umsatzwachstum_5J: metrics.revenueGrowth5Y + " %",
  Gewinnwachstum_5J: metrics.epsGrowth5Y + " %",
  Nettogewinnmarge_TTM: metrics.netProfitMarginTTM + " %",
  Bruttomarge_TTM: metrics.grossMarginTTM + " %",
  Eigenkapitalrendite_TTM: metrics.roeTTM + " %",

  // Quick Ratio & Verschuldungsgrad: keine Einheit (Ratios).
  Quick_Ratio_TTM: metrics.quickRatioQuarterly,
  Verschuldungsgrad_TTM: metrics["totalDebt/totalEquityQuarterly"],

  // 52-Wochen Hoch/Tief in USD.
  "52_Wochen_Hoch": metrics["52WeekHigh"] + " USD",
  "52_Wochen_Tief": metrics["52WeekLow"] + " USD",

  // Beta: keine Einheit (Verhältnis).
  Beta: metrics.beta,

  // YTD Kursveränderung: Prozent.
  YTD_Kursveränderung: metrics.yearToDatePriceReturnDaily + " %",

  // Dividendenrendite & Ausschüttungsquote: Prozent.
  Dividendenrendite_TTM: metrics.currentDividendYieldTTM + " %",
  Ausschüttungsquote_TTM: metrics.payoutRatioTTM + " %"
};

// Als JSON-String für den nächsten Node
const jsonString = JSON.stringify(relevanteDaten, null, 2);

return {
  json: {
    output: jsonString
  }
};
